// Fast-fail valid-object responder for ElevenLabs conversation_initiation_client_data.
// Hard floor: returns a valid object with every defined dynamic variable, even when every upstream is dead.
// Mirrors src/webhook/client-initiation.ts in the repo.
const body = $input.first().json.body || $input.first().json;
const callerId = body.caller_id || '';
const agentId = body.agent_id || '';

// Default specs — keep in sync with templates/elevenlabs-agents/template-system-prompt-v1.md
const specs = [
  {identifier: 'system_prompt_context', type: 'string', default: 'none'},
  {identifier: 'agent_name', type: 'string', default: 'the assistant'},
  {identifier: 'company_name', type: 'string', default: 'this business'},
  {identifier: 'primary_language', type: 'string', default: 'English'},
  {identifier: 'transfer_enabled', type: 'boolean', default: false},
  {identifier: 'agent_voice_marker', type: 'string', default: ''}
];

const dynamic_variables = {};
for (const spec of specs) {
  dynamic_variables[spec.identifier] = spec.default;
}

// TODO: enrich with CRM lookup of callerId here, racing against a 2s timeout.
// On any failure leave the defaults intact.

return [{json: {
  type: 'conversation_initiation_client_data',
  dynamic_variables
}}];
